from collections import Counter

def solve(nums: list[int], queries: list[list[int]]) -> list[int]:
    ans = []
    for l, r, t in queries:
        sub = nums[l:r+1]
        cnt = Counter(sub)
        max_freq = -1
        candidates = []
        for num, freq in cnt.items():
            if freq >= t:
                if freq > max_freq:
                    max_freq = freq
                    candidates = [num]
                elif freq == max_freq:
                    candidates.append(num)
        if not candidates:
            ans.append(-1)
        else:
            ans.append(min(candidates))
    return ans
